import xml.etree.ElementTree as ET
from xml.dom import minidom
import os
from typing import Optional, Dict, Any
import re


def validate_xml_document(
    file_path: str,
    max_file_size_mb: int = 10,
    allowed_root_tags: Optional[list] = None,
    schema_path: Optional[str] = None
) -> Dict[str, Any]:
    """
    Reads and validates an XML document uploaded by a user.
    
    Args:
        file_path: Path to the XML file
        max_file_size_mb: Maximum allowed file size in MB
        allowed_root_tags: List of allowed root tag names (None = any)
        schema_path: Path to XSD schema file for validation (optional)
    
    Returns:
        Dictionary containing validation results and parsed data
    """
    result = {
        'valid': False,
        'errors': [],
        'warnings': [],
        'root_tag': None,
        'element_count': 0,
        'file_size_mb': 0,
        'parsed_tree': None
    }
    
    # Check if file exists
    if not os.path.exists(file_path):
        result['errors'].append(f"File not found: {file_path}")
        return result
    
    # Check file size
    file_size_bytes = os.path.getsize(file_path)
    file_size_mb = file_size_bytes / (1024 * 1024)
    result['file_size_mb'] = round(file_size_mb, 2)
    
    if file_size_mb > max_file_size_mb:
        result['errors'].append(
            f"File size ({file_size_mb:.2f} MB) exceeds maximum allowed size ({max_file_size_mb} MB)"
        )
        return result
    
    # Check if file is empty
    if file_size_bytes == 0:
        result['errors'].append("File is empty")
        return result
    
    # Try to parse XML
    try:
        tree = ET.parse(file_path)
        root = tree.getroot()
        result['parsed_tree'] = tree
        result['root_tag'] = root.tag
        
    except ET.ParseError as e:
        result['errors'].append(f"XML parsing error: {str(e)}")
        return result
    except Exception as e:
        result['errors'].append(f"Error reading file: {str(e)}")
        return result
    
    # Validate root tag if restrictions are specified
    if allowed_root_tags is not None and root.tag not in allowed_root_tags:
        result['errors'].append(
            f"Root tag '{root.tag}' not in allowed tags: {allowed_root_tags}"
        )
        return result
    
    # Count elements
    result['element_count'] = len(list(root.iter()))
    
    # Check for well-formedness issues
    try:
        with open(file_path, 'r', encoding='utf-8') as f:
            content = f.read()
            
        # Check for common issues
        if '<?xml' not in content[:100]:
            result['warnings'].append("Missing XML declaration")
        
        # Check for potentially malicious content
        if re.search(r'<!ENTITY', content, re.IGNORECASE):
            result['warnings'].append("Document contains ENTITY declarations (potential XXE risk)")
        
        if re.search(r'<!DOCTYPE.*SYSTEM', content, re.IGNORECASE):
            result['warnings'].append("Document contains external SYSTEM references")
            
    except UnicodeDecodeError:
        result['warnings'].append("File encoding issue detected")
    except Exception as e:
        result['warnings'].append(f"Additional validation warning: {str(e)}")
    
    # Validate against XSD schema if provided
    if schema_path:
        try:
            from lxml import etree
            
            if not os.path.exists(schema_path):
                result['errors'].append(f"Schema file not found: {schema_path}")
                return result
            
            with open(schema_path, 'r') as schema_file:
                schema_root = etree.XML(schema_file.read().encode())
            
            schema = etree.XMLSchema(schema_root)
            
            with open(file_path, 'r') as xml_file:
                xml_doc = etree.parse(xml_file)
            
            if not schema.validate(xml_doc):
                for error in schema.error_log:
                    result['errors'].append(f"Schema validation error: {error.message}")
                return result
                
        except ImportError:
            result['warnings'].append("lxml not available for XSD validation")
        except Exception as e:
            result['errors'].append(f"Schema validation error: {str(e)}")
            return result
    
    # If we got here, validation passed
    if not result['errors']:
        result['valid'] = True
    
    return result


def read_xml_to_dict(file_path: str) -> Optional[Dict[str, Any]]:
    """
    Reads an XML file and converts it to a dictionary structure.
    
    Args:
        file_path: Path to the XML file
    
    Returns:
        Dictionary representation of XML or None if invalid
    """
    validation_result = validate_xml_document(file_path)
    
    if not validation_result['valid']:
        return None
    
    def element_to_dict(element):
        result = {}
        
        # Add attributes
        if element.attrib:
            result['@attributes'] = element.attrib
        
        # Add text content
        if element.text and element.text.strip():
            result['#text'] = element.text.strip()
        
        # Add child elements
        for child in element:
            child_data = element_to_dict(child)
            
            if child.tag in result:
                # Convert to list if multiple elements with same tag
                if not isinstance(result[child.tag], list):
                    result[child.tag] = [result[child.tag]]
                result[child.tag].append(child_data)
            else:
                result[child.tag] = child_data
        
        # If element has only text and no attributes/children, return just the text
        if len(result) == 1 and '#text' in result:
            return result['#text']
        
        return result if result else None
    
    tree = validation_result['parsed_tree']
    root = tree.getroot()
    
    return {root.tag: element_to_dict(root)}